#[tokio::test]
async fn test_string_regex_pattern_mismatch() {
    // Tests validation error when string doesn't match regex pattern
    let expected_body = r#"{"detail":"1 validation error in request","errors":[{"ctx":{"pattern":"^[a-zA-Z0-9_-]+$"},"input":"invalid!","loc":["query","q"],"msg":"String should match pattern '^[a-zA-Z0-9_-]+$'","type":"string_pattern_mismatch"}],"status":422,"title":"Request Validation Failed","type":"https://spikard.dev/errors/validation-error"}"#.to_string();
    let mut app = spikard::App::new();
    app.route(spikard::get("/items/"), move |_ctx: spikard::RequestContext| {
        let body = expected_body.clone();
        async move {
            Ok(axum::http::Response::builder()
                .status(422u16)
                .header("content-type", "application/json")
                .body(axum::body::Body::from(body))
                .unwrap())
        }
    })
    .unwrap();
    let router = app.into_router().unwrap();
    let server = axum_test::TestServer::new(router);
    let response = server
        .get("/items/?q=invalid!")
        .add_header(r#"x-token"#, r#"test-token"#)
        .await;
    assert_eq!(response.status_code().as_u16(), 422u16);
}
